import{_ as e,o as i,c as n,a4 as r}from"./chunks/framework.wrug7QjT.js";const u=JSON.parse('{"title":"Finland — Country Profile","description":"Comprehensive guide to Finland for transgender relocation: legal recognition, healthcare, cost of living, visa pathways, community, and risks.","frontmatter":{"layout":"doc","title":"Finland — Country Profile","description":"Comprehensive guide to Finland for transgender relocation: legal recognition, healthcare, cost of living, visa pathways, community, and risks."},"headers":[],"relativePath":"countries/finland/index.md","filePath":"countries/finland/index.md","lastUpdated":1781006640000}'),a={name:"countries/finland/index.md"};function o(s,t,l,d,c,g){return i(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="🇫🇮-finland" tabindex="-1"><span style="color:#002f6c;">🇫🇮 Finland</span> <a class="header-anchor" href="#🇫🇮-finland" aria-label="Permalink to &quot;&lt;span style=&quot;color: #002f6c;&quot;&gt;🇫🇮 Finland&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Helsinki</td></tr><tr><td><strong>Population</strong></td><td>~5.5 million</td></tr><tr><td><strong>Language</strong></td><td>Finnish, Swedish (English widely spoken)</td></tr><tr><td><strong>Currency</strong></td><td>Euro (EUR)</td></tr><tr><td><strong>EU Member</strong></td><td>Yes</td></tr><tr><td><strong>Equaldex Score</strong></td><td>86</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>4/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 8, 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><ul><li><strong>Gender Recognition:</strong> Self-ID since 2023. Adults 18+ can self-declare to the Digital and Population Data Services Agency (DVV). No medical requirements, no surgery, no therapy.</li><li><strong>Anti-Discrimination Law:</strong> Comprehensive, covering gender identity in employment, housing, and services (Non-Discrimination Act 2014).</li><li><strong>Hate Crime Laws:</strong> Gender identity included in criminal code.</li><li><strong>Same-Sex Marriage:</strong> Legal since 2017.</li><li><strong>Conversion Therapy:</strong> Banned (2025).</li></ul><h2 id="healthcare-reality" tabindex="-1">Healthcare Reality <a class="header-anchor" href="#healthcare-reality" aria-label="Permalink to &quot;Healthcare Reality&quot;">​</a></h2><ul><li><strong>HRT Access:</strong> Informed consent available. Helsinki&#39;s HUS Gender Identity Clinic is the main provider. Wait times: 6–12 months for first appointment.</li><li><strong>HRT Cost:</strong> €5–15 per prescription (public). €30–50/month private.</li><li><strong>Regional variation:</strong> Helsinki has good access. Other regions require travel to Helsinki for specialist care.</li><li><strong>Surgery:</strong> Publicly funded (HUS clinic). Wait times: 1–2 years.</li></ul><h2 id="where-to-live" tabindex="-1">Where to Live <a class="header-anchor" href="#where-to-live" aria-label="Permalink to &quot;Where to Live&quot;">​</a></h2><ul><li><strong>Helsinki:</strong> Largest trans community. Best healthcare access. 1-bedroom: €900–1,400/month.</li><li><strong>Tampere:</strong> Small but active community. 1-bedroom: €700–1,000/month.</li><li><strong>Turku:</strong> Small community. Good university town. 1-bedroom: €600–900/month.</li><li><strong>Rural Finland:</strong> Very limited trans community. High social isolation risk.</li></ul><p><strong>Monthly budget (Helsinki):</strong> €1,500–2,500.</p><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Income Req.</th><th>Processing</th><th>Leads to PR?</th></tr></thead><tbody><tr><td>Work Visa</td><td>Job offer required</td><td>2–6 months</td><td>Yes</td></tr><tr><td>Student Visa</td><td>€6,720/year (blocked account)</td><td>1–3 months</td><td>Yes (post-study)</td></tr><tr><td>Startup Visa</td><td>Business plan evaluation</td><td>2–4 months</td><td>Yes</td></tr><tr><td>EU Freedom of Movement</td><td>N/A</td><td>Immediate</td><td>Yes</td></tr><tr><td>Asylum</td><td>N/A</td><td>6–18 months</td><td>Yes (55–75% grant rate for LGBTQ+)</td></tr></tbody></table><h2 id="known-risks" tabindex="-1">Known Risks <a class="header-anchor" href="#known-risks" aria-label="Permalink to &quot;Known Risks&quot;">​</a></h2><ol><li><strong>Long, dark winters</strong> — extreme seasonal affect. Helsinki gets 6 hours of daylight in December.</li><li><strong>Language:</strong> Finnish is exceptionally difficult. Swedish is easier but less widely spoken as a first language.</li><li><strong>Healthcare wait times</strong> for the Gender Identity Clinic are long.</li><li><strong>Small population</strong> means limited dating pool and community.</li><li><strong>High alcohol prices</strong> and limited social life outside Helsinki.</li></ol><p><em>Sources: Seta (LGBTQ+ organisation), HUS Gender Identity Clinic, TGEU, Equaldex. Last verified: June 8, 2026.</em></p>',14)])])}const m=e(a,[["render",o]]);export{u as __pageData,m as default};
